var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"지시하신 서류업무 전부 끝냈습니다.","JPN":"指示された書類業務はすべて終わらせました。","ENG":"I've finished all the paperwork as you instructed.","TWN":"您指示的文書工作已經全部完成。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"그래, 고생했어. 곧 근무 교대할 준비해.","JPN":"ああ、ご苦労様。交代準備をしていいぞ。","ENG":"Well done. Someone will be here shortly to take your shift.","TWN":"好，辛苦了。準備換班吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"......저기, 그런데 제 3호 독방에 있는 저 죄수는 뭡니까?","JPN":"あの……ところで第3号独房にいる囚人は何者ですか？","ENG":"By the way, who's the prisoner in the third solitary confinement cell?","TWN":"……那個，3號單人房的罪犯是誰？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"독방은 면회 금지일 텐데 사람들도 매일 찾아오네요.","JPN":"独房は面会禁止なのに、毎日誰かしら訪ねてくるのが不思議でして。","ENG":"I thought inmates in solitary weren't allowed visitors, but he's got them every day.","TWN":"單人房明明禁止會面，卻每天都有人來看他。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"거기다가 죄수복도 안 입고 있고......","JPN":"それに、受刑者用の服も着ていないですし……","ENG":"Plus, he's not even in uniform...","TWN":"而且他也沒穿囚衣……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"......알면 다쳐.","JPN":"……知らなくていいことだってある。","ENG":"Trust me, the less you know, the better.","TWN":"……別想知道太多。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"괜히 쓸데없는 데 관심 가지지 말고 모른 척 해.","JPN":"興味を持つ必要はない、知らないフリをしろ。","ENG":"Stop getting nosy and just pretend you didn't see anything.","TWN":"別多管閒事，假裝什麼都不知道。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"다 널 위해 하는 말이야.","JPN":"これは君のための忠告だ。","ENG":"This is all for your sake.","TWN":"這都是為你好。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WARDER_NPC_OLD_NULL","text":{"KOREA":"소장님 지시기도 하니까 괜히 문제 일으키지 말고 입 단속 잘하라고.","JPN":"所長の指示でもあるから、余計なトラブルは控えろ。あと、君も含めて周りの口止めもな。","ENG":"The warden specifically demanded this arrangement, so try to keep your mouth shut.","TWN":"而且這也是所長大人的指示，不要惹事，管好自己的嘴。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WARDER_NPC_NEW_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Sir?","TWN":"什麼……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......다시 말해 봐.","JPN":"……もう一度言ってみろ。","ENG":"... Let me hear that again.","TWN":"……再說一遍。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"면목 없습니다, 보스.","JPN":"申し訳ありません、ボス。","ENG":"Sorry, boss.","TWN":"對不起，老闆。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"누가 사과하라고 했나? 다시 말해 보라고.","JPN":"謝れとは言ってない。もう一度言ってみろ。","ENG":"I didn't ask for an apology. Tell me what happened again.","TWN":"誰讓你道歉了？我說再說一遍。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"......저희가 도착했을 때는 이미 치명상을 입은 상태였습니다.","JPN":"……私たちが到着した時は、すでに致命傷を負った状態でした。","ENG":"He was already critically wounded by the time we got to him.","TWN":"……我們抵達時，他已經受了致命傷。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그러니까...... 도현이가 죽었다는 말이야?","JPN":"だから……リョウが死んだと？","ENG":"Are you telling me... Dohyun is dead?","TWN":"也就是說……道賢死了？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"네, 최선을 다했지만 어쩔 수 없이......","JPN":"はい、最善を尽くしましたが惜しくも……","ENG":"We tried our best, but I'm afraid so...","TWN":"是，我們盡全力搶救了，可是……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"부디 용서해 주십시오.","JPN":"どうかお許しください。","ENG":"Please forgive us.","TWN":"請您原諒。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"짜식.","JPN":"そんなにビビるなよ。","ENG":"Relax.","TWN":"你這小子，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뭐 그럴 수도 있지, 그렇게 굳어 있을 필요 없어.","JPN":"まあ、そんなこともある。顔を上げろ。","ENG":"What happened just happened. No need to get all nervous about it.","TWN":"就因為這點小事，何必那麼緊張。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"내 아우이긴 했지만 예전부터 죽을 짓만 골라 하는 녀석이었거든.","JPN":"俺の弟分ではあるが、昔からヘイトばかり集めていたからな。","ENG":"He may have been my brother, but he's always dug his own graves.","TWN":"他是我弟弟，我早就知道他總是惹事生非，自尋死路。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"언젠가는 이런 날이 올 거라고 생각했었어.","JPN":"いつかこんな日が来るとは思っていた。","ENG":"I had a feeling this day would eventually come.","TWN":"我知道這一天總會到來。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"죄송합니다.","JPN":"申し訳ありません。","ENG":"Sorry, sir.","TWN":"非常抱歉。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"됐다니까? 그건 그렇고 어떤 놈들 짓이었나?","JPN":"もういいさ。で、どこの奴にやられたんだ？","ENG":"I told you, it's fine. By the way, who was responsible for this?","TWN":"別說了，先告訴我他是被什麼人殺的？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"그건...... 신경 쓰실 필요 없습니다. 제가 알아서 처리를......","JPN":"それは……気になさることではありません。私のほうで処理……","ENG":"Erm... you don't need to concern yourself about that, sir. I'll take care of it.","TWN":"那個……不用您操心。我會安排人處理……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"괜찮아. 그래도 내 아우였잖아.","JPN":"お前こそ気を使うな。あいつは俺の弟分だろ。","ENG":"No worries. He was my brother, after all.","TWN":"不用了，他畢竟是我弟弟。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"마지막 가는 길 보내준 친구들 얼굴은 알아야지.","JPN":"見送る前に、あいつをいじめた連中の顔ぐらい確かめておかなきゃな。","ENG":"I ought to know who's responsible for his departure.","TWN":"我好歹應該看看到底是誰殺了我弟弟吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"그렇다고 친동생인 건 아니지 않습니까?","JPN":"しかし血の繋がりのある兄弟ではないですし……","ENG":"But it's not like he was your brother by birth, sir.","TWN":"但他畢竟不是您的親弟弟呀？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"말씀하신 것처럼 도현이는 예전부터 조직에 해만 끼치던 놈입니다.","JPN":"おっしゃるとおり、リョウは昔から組織に迷惑ばかりかけていた奴です。","ENG":"As you've said, Dohyun has been nothing but trouble to our organization.","TWN":"如您所說，道賢一直以來給組織帶來了很多麻煩。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"굳이 그런 놈을 위해 보스께서 직접 움직이실 필요는......","JPN":"わざわざあんな奴のために、ボスがみずから動く必要は……","ENG":"I see no reason you'd have to respond yourself to this—","TWN":"老闆沒必要為那種傢伙親自動手……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"하, 이 ■끼. 혓바닥 많이 길어졌네.","JPN":"は。お前さ、ずいぶん生意気な口を叩くじゃないか。","ENG":"Ah, so you think you know better now?","TWN":"哈，你什麼時候變得這麼囉嗦了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CRIMINAL_NPC_INVADER_NULL","text":{"KOREA":"네......?","JPN":"はい……？","ENG":"Sir?","TWN":"什麼……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"여기 눌러 앉아 있으니까 내가 같은 말 두 번 하는 거 싫어한다는 것도 까먹었냐?","JPN":"ここでのんびりしているうちに、俺が同じ言葉を2回言うのが嫌いだということも忘れたのか？","ENG":"Did you forget how much I hate repeating myself just because I've been cooped up here so long?","TWN":"你難道忘了我最討厭重複已經說過的話了嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그리고 니가 예전부터 도현이 구역 잡아먹으려고 노리고 있었던 것도 내가 모를 것 같아?","JPN":"あと、お前が昔からリョウの縄張りを狙っていたことに俺が気付いてないとでも？","ENG":"And did you think I wouldn't know about how much you've wanted to take over Dohyun's territory?","TWN":"你以為我不知道你從很久以前開始就對道賢的領地虎視眈眈嗎？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"보나마나 일부러 늑장 부리다가 일 끝난 다음에나 움직였겠지. 아니야?","JPN":"どうせわざと遅らせて、終わった頃に動いたんだろ？","ENG":"I bet you were planning to put this off till everything blew over. Am I wrong?","TWN":"肯定是等事情結束後才去救他的，對不對？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"어이, 대답해 봐. 어이......?","JPN":"おい、答えろ。なあ……？","ENG":"Hey, I asked you a question. Answer me...","TWN":"喂，回答我。喂……？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"뭐야? 죽었잖아.","JPN":"なんだ？　死んじまったのか。","ENG":"Huh? He's dead.","TWN":"嗯？死掉了嗎。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"......시신은 어떻게 할까요?","JPN":"……死体はどうしましょうか？","ENG":"... What should we do with the body?","TWN":"……屍體要怎麼處理？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"병원에 연락해서 장기기증이라도 해.","JPN":"病院に連絡して臓器でも提供しろ。","ENG":"Call the hospital and donate his organs.","TWN":"都捐給醫院吧。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"못난 부하라도 사회에 보탬은 돼야지.","JPN":"仕事ができない部下でも社会貢献になるなら使ってもらわないとな。","ENG":"He might as well as give something back to society.","TWN":"好讓這沒用的傢伙為社會做點貢獻。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"......그렇게 조치하겠습니다.","JPN":"……承知しました。","ENG":"Will do, sir.","TWN":"……我了解了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그리고 소장에게 연락해서 나 당분간 외출 나간다고 해.","JPN":"あと、所長に連絡して俺はしばらく出かけると伝えろ。","ENG":"And tell the warden I'll be taking off for a while.","TWN":"告訴所長，這幾天我要外出。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"도현이 건드린 놈들 신상명세 알아오고.","JPN":"リョウの奴に手を出した連中の詳細も調べろ。","ENG":"And figure out who whacked Dohyun.","TWN":"你去調查一下殺死道賢的傢伙們的底細。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"알겠습니다. 조직원들도 모두 소집할까요?","JPN":"了解しました。組織員は全員招集しますか？","ENG":"Understood, sir. Should I round up all the boys?","TWN":"明白，要不要召集其他組織成員？"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"그래. 이렇게 내게 이빨을 들이댄 녀석도 오랜만이잖아? ","JPN":"そうだな。俺に牙を剥く奴は久しぶりだろ？ ","ENG":"Yes. It's been a while since anyone's challenged me so directly. ","TWN":"當然，畢竟好久沒有人敢這樣公然挑釁我了。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"가끔은 당연한 사실도 상기시켜줄 필요가 있는 법이지.","JPN":"当然の事実でも、たまには思い出させてやる必要があるのさ。","ENG":"It's worth reminding folks of the truth once in a while, even if it's painfully obvious.","TWN":"理所當然的事情也需要偶爾提醒一下。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"이번 기회에 이 도시에 다시 한 번 알려 주자고.","JPN":"これを機にこの都市の人間どもにしっかり思い知らせてやろう。","ENG":"We might as take this opportunity to remind everyone in this city...","TWN":"趁這次機會，我要讓這座城市明白，"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_NULL","text":{"KOREA":"성냥을 가지고 장난을 치면 숲이 모조리 타 버린다는 걸 말이야.","JPN":"マッチでイタズラすると、森は全焼してしまうということをな。","ENG":"... that playing with matches could burn down the entire forest.","TWN":"玩火柴時一個不小心可能會燒掉整座森林。"},"stage":{"bg":"PRISON_NIGHT","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MATCHMAN_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};